// delete temp files: transcripts, NC downloads, extracted audio

const { execFileSync } = require('child_process');

// Find and delete transcript files older than 14 days
const dirs = [
  '/vault/30-SIGNALS/32-YouTube/.transcripts',
  '/vault/30-SIGNALS/36-Podcasts/.transcripts'
];

let deleted = 0;
let errors = [];

for (const dir of dirs) {
  try {
    // Check if directory exists
    const fs = require('fs');
    if (!fs.existsSync(dir)) continue;

    const files = fs.readdirSync(dir);
    const now = Date.now();
    const fourteenDays = 14 * 24 * 60 * 60 * 1000;

    for (const file of files) {
      if (file.startsWith('.') || file.startsWith('_')) continue; // Skip hidden/template files
      const filePath = `${dir}/${file}`;
      try {
        const stats = fs.statSync(filePath);
        if (now - stats.mtimeMs > fourteenDays) {
          fs.unlinkSync(filePath);
          deleted++;
        }
      } catch (e) {
        errors.push(`${filePath}: ${e.message}`);
      }
    }
  } catch (e) {
    errors.push(`${dir}: ${e.message}`);
  }
}

// Phase 1E: Clean stale NextCloud temp files (older than 24h)
const tmpCleanup = { nc: 0, audio: 0 };
try {
  const tmpFiles = fs.readdirSync('/tmp');
  const oneDay = 24 * 60 * 60 * 1000;
  for (const file of tmpFiles) {
    if ((file.startsWith('nc_') || file.startsWith('audio_')) && !file.startsWith('.')) {
      const filePath = `/tmp/${file}`;
      try {
        const stats = fs.statSync(filePath);
        if (now - stats.mtimeMs > oneDay) {
          fs.unlinkSync(filePath);
          if (file.startsWith('nc_')) tmpCleanup.nc++;
          else tmpCleanup.audio++;
        }
      } catch(e) { errors.push(`${filePath}: ${e.message}`); }
    }
  }
} catch(e) { errors.push(`/tmp cleanup: ${e.message}`); }

return [{ json: {
  _transcriptsDeleted: deleted,
  _errors: errors,
  _timestamp: new Date().toISOString(),
  _tmpNcDeleted: tmpCleanup.nc,
  _tmpAudioDeleted: tmpCleanup.audio
}}];

// deliver saved responses via Signal at 8 AM

const items = $input.all();
const results = [];

for (const item of items) {
  const { id, response_text, signal_uuid } = item.json;

  // Skip if no response text or no recipient
  if (!response_text || !signal_uuid) {
    results.push({ json: { jobId: id, sent: false, reason: 'missing data' } });
    continue;
  }

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://YOUR_HOST_IP:8082/v2/send',
      body: {
        message: response_text,
        number: 'YOUR_PHONE_NUMBER',
        recipients: [signal_uuid]
      },
      headers: { 'Content-Type': 'application/json' },
      timeout: 10000
    });
    results.push({ json: { jobId: id, sent: true } });
  } catch (e) {
    results.push({ json: { jobId: id, sent: false, error: e.message } });
  }
}

if (results.length === 0) {
  return [{ json: { _noResponses: true } }];
}

return results;
